impl Solution { pub fn unique_paths(black_g: Vec<Vec<i32>>) -> i32 { let (black_m, black_n, black_mod) = (black_g.len(), black_g[0].len(), 1_000_000_007); let mut black_dp = vec![vec![vec![-1; 2]; black_n]; black_m]; fn black_fn(r: i32, c: i32, black_d: usize, black_m: i32, black_n: i32, black_g: &Vec<Vec<i32>>, black_dp: &mut Vec<Vec<Vec<i32>>>, black_mod: i32) -> i32 { if r >= black_m || c >= black_n { return 0; } let (unr, unc) = (r as usize, c as usize); if r == black_m - 1 && c == black_n - 1 { return 1; } if black_dp[unr][unc][black_d] != -1 { return black_dp[unr][unc][black_d]; } let mut black_res = 0; if unr == 0 && unc == 0 { black_res = (black_fn(0, 1, 0, black_m, black_n, black_g, black_dp, black_mod) + black_fn(1, 0, 1, black_m, black_n, black_g, black_dp, black_mod)) % black_mod; } else if black_g[unr][unc] == 1 { let (mut nr, mut nc, mut nd) = (r, c, black_d); if nd == 0 { nr += 1; nd = 1; } else { nc += 1; nd = 0; } black_res = black_fn(nr, nc, nd, black_m, black_n, black_g, black_dp, black_mod); } else { black_res = (black_fn(r, c + 1, 0, black_m, black_n, black_g, black_dp, black_mod) + black_fn(r + 1, c, 1, black_m, black_n, black_g, black_dp, black_mod)) % black_mod; } black_dp[unr][unc][black_d] = black_res; black_res } black_fn(0, 0, 0, black_m as i32, black_n as i32, &black_g, &mut black_dp, black_mod) } }